import redis
import json
import logging
from typing import Optional, Dict, Any
from datetime import timedelta

class RedisCache:
    def __init__(self, redis_nodes: list, password: str = None, decode_responses: bool = True):
        self.redis_nodes = redis_nodes
        self.password = password
        self.decode_responses = decode_responses
        self.redis_connections = []
        self._connect_to_cluster()
    
    def _connect_to_cluster(self):
        """Establish connections to all Redis nodes in the cluster"""
        for node in self.redis_nodes:
            try:
                connection = redis.Redis(
                    host=node['host'],
                    port=node['port'],
                    password=self.password,
                    decode_responses=self.decode_responses,
                    socket_connect_timeout=5,
                    socket_timeout=5,
                    retry_on_timeout=True,
                    health_check_interval=30
                )
                connection.ping()
                self.redis_connections.append(connection)
                logging.info(f"Connected to Redis node {node['host']}:{node['port']}")
            except Exception as e:
                logging.error(f"Failed to connect to Redis node {node['host']}:{node['port']}: {e}")
                raise
    
    def set_user_session(self, user_id: str, session_data: Dict[str, Any], ttl_minutes: int = 30) -> bool:
        """Store user session data with TTL"""
        try:
            key = f"user:session:{user_id}"
            ttl_seconds = ttl_minutes * 60
            data = json.dumps(session_data)
            
            # Use first connection for setting
            connection = self.redis_connections[0]
            result = connection.setex(key, ttl_seconds, data)
            return result
        except Exception as e:
            logging.error(f"Failed to set user session for user {user_id}: {e}")
            return False
    
    def get_user_session(self, user_id: str) -> Optional[Dict[str, Any]]:
        """Retrieve user session data"""
        try:
            key = f"user:session:{user_id}"
            connection = self.redis_connections[0]
            data = connection.get(key)
            
            if data:
                return json.loads(data)
            return None
        except Exception as e:
            logging.error(f"Failed to get user session for user {user_id}: {e}")
            return None
    
    def set_api_key(self, user_id: str, api_key: str, ttl_hours: int = 24) -> bool:
        """Store API key with TTL"""
        try:
            key = f"user:api_key:{user_id}"
            ttl_seconds = ttl_hours * 3600
            
            connection = self.redis_connections[0]
            result = connection.setex(key, ttl_seconds, api_key)
            return result
        except Exception as e:
            logging.error(f"Failed to set API key for user {user_id}: {e}")
            return False
    
    def get_api_key(self, user_id: str) -> Optional[str]:
        """Retrieve API key"""
        try:
            key = f"user:api_key:{user_id}"
            connection = self.redis_connections[0]
            return connection.get(key)
        except Exception as e:
            logging.error(f"Failed to get API key for user {user_id}: {e}")
            return None
    
    def delete_user_data(self, user_id: str) -> bool:
        """Delete all user data"""
        try:
            connection = self.redis_connections[0]
            keys = connection.keys(f"user:*:{user_id}")
            if keys:
                connection.delete(*keys)
                return True
            return False
        except Exception as e:
            logging.error(f"Failed to delete user data for user {user_id}: {e}")
            return False
    
    def get_connection_stats(self) -> Dict[str, Any]:
        """Get connection statistics"""
        stats = {}
        for i, connection in enumerate(self.redis_connections):
            try:
                info = connection.info()
                stats[f"node_{i}"] = {
                    "host": connection.host,
                    "port": connection.port,
                    "connected": True,
                    "used_memory": info.get('used_memory_human', 'N/A'),
                    "connected_clients": info.get('connected_clients', 'N/A')
                }
            except Exception as e:
                stats[f"node_{i}"] = {"connected": False, "error": str(e)}
        return stats

